### 7. `assertUserIsInstructor` Definition
**File:** `/scratch/platform/supabase/functions/_shared/HandlerUtils.ts` (lines 73-110)

**Full definition:**
```typescript
export async function assertUserIsInstructor(courseId: number, authHeader: string) {
  const supabase = createClient<Database>(Deno.env.get("SUPABASE_URL")!, Deno.env.get("SUPABASE_ANON_KEY")!, {
    global: {
      headers: { Authorization: authHeader }
    }
  });
  const token = authHeader.replace("Bearer ", "");
  const {
    data: { user },
    error
  } = await supabase.auth.getUser(token);
  if (error) {
    console.error(error);
  }
  if (!user) {
    throw new SecurityError("User not found");
  }
  const { data: enrollment } = await supabase
    .from("user_roles")
    .select("*")
    .eq("user_id", user.id)
    .eq("class_id", courseId)
    .eq("role", "instructor")
    .maybeSingle();
  if (!enrollment) {
    //OK if user is an ADMIN of any course
    const { data: adminEnrollment } = await supabase
      .from("user_roles")
      .select("*")
      .eq("user_id", user.id)
      .eq("role", "admin");
    if (adminEnrollment && adminEnrollment.length > 0) {
      return { supabase, enrollment: adminEnrollment[0] };
    }
    throw new SecurityError("User is not an instructor for this course");
  }
  return { supabase, enrollment };
}
```

**Return type:** `{ supabase: SupabaseClient<Database>, enrollment: UserRole }`

**Related:** `assertUserIsInstructorOrServiceRole` (lines 117-134) wraps this and allows service role requests.

