export default async function AdminLayout({ children }: AdminLayoutProps) {
  const supabase = await createClient();

  // Get current user
  const {
    data: { user },
    error: authError
  } = await supabase.auth.getUser();

  if (authError || !user) {
    redirect("/sign-in");
  }

  // Check if user has admin role
