      if (hasLocations) {
        if (!Array.isArray(unitObj["locations"]) || (unitObj["locations"] as unknown[]).length === 0) {
          return { isValid: false, error: `gradedParts[${i}].gradedUnits[${j}].locations must be a non-empty array` };
