        }

        if (hasLinearScoring) {
          const linearScoring = unitObj["linearScoring"];
          if (!linearScoring || typeof linearScoring !== "object") {
            return {
              isValid: false,
              error: `gradedParts[${i}].gradedUnits[${j}].linearScoring must be an object`
