      "type": "object",
      "description": "Build configuration for the autograder.",
      "required": ["preset", "cmd", "artifacts", "linter"],
      "properties": {
        "preset": { "type": "string", "enum": ["java-gradle"] },
        "cmd": { "type": "string", "description": "Build command to run." },
        "artifacts": { "type": "array", "items": { "type": "string" } },
        "linter": {
          "type": "object",
          "required": ["preset", "policy"],
          "properties": {
            "preset": { "type": "string", "enum": ["checkstyle"] },
            "policy": { "type": "string", "enum": ["fail", "warn", "ignore"] }
          }
        }
      }
    },
    "gradedParts": {
      "type": "array",
      "description": "The graded parts of the assignment.",
      "items": {
        "type": "object",
        "required": ["name", "gradedUnits"],
        "properties": {
          "name": { "type": "string" },
          "gradedUnits": {
            "type": "array",
            "items": {
              "anyOf": [
                {
                  "type": "object",
                  "title": "Mutation test unit",
                  "required": ["name", "locations"],
                  "properties": {
                    "name": { "type": "string" },
                    "locations": {
                      "type": "array",
                      "minItems": 1,
                      "items": { "type": "string", "description": "Format: \"file:line-line\"" }
