                    "breakPoints": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "required": ["minimumMutantsDetected", "pointsToAward"],
                        "properties": {
                          "minimumMutantsDetected": { "type": "number" },
                          "pointsToAward": { "type": "number" }
