                      }
                    },
                    "linearScoring": {
                      "type": "object",
                      "required": ["points", "total_faults"],
                      "properties": {
                        "points": { "type": "number" },
                        "total_faults": { "type": "number" }
                      }
                    }
                  }
                },
                {
                  "type": "object",
                  "title": "Regular test unit",
                  "required": ["name", "tests", "points"],
                  "properties": {
                    "name": { "type": "string" },
                    "tests": {
                      "anyOf": [
                        { "type": "string" },
                        { "type": "array", "items": { "type": "string" } }
                      ],
                      "description": "Test selector(s), format \"[T#.#]\"."
                    },
                    "points": { "type": "number" },
                    "testCount": { "type": "number" }
                  }
                }
              ]
            }
          }
        }
      }
