function buildFlagsFromRole(
  features: { name: string; enabled: boolean }[] | null | undefined
): Record<CourseFeatureName, boolean> {
  const out = {} as Record<CourseFeatureName, boolean>;
  for (const def of MANAGEABLE_COURSE_FEATURES) {
