    INSERT INTO public.user_roles (user_id, class_id, role, public_profile_id, private_profile_id)
    VALUES (v_user_id, p_class_id, 'instructor', v_public_profile_id, v_private_profile_id);
END;
$$;

----------------------------------------------------------------------------------------
-- 6. Grants
----------------------------------------------------------------------------------------

